template<typename ContainerAllocator1, typename ContainerAllocator2>
bool operator==(const ::px4_msgs::VehicleCommand_<ContainerAllocator1> & lhs, const ::px4_msgs::VehicleCommand_<ContainerAllocator2> & rhs)
{
  return lhs.timestamp == rhs.timestamp &&
    lhs.param1 == rhs.param1 &&
    lhs.param2 == rhs.param2 &&
    lhs.param3 == rhs.param3 &&
    lhs.param4 == rhs.param4 &&
    lhs.param5 == rhs.param5 &&
    lhs.param6 == rhs.param6 &&
    lhs.param7 == rhs.param7 &&
    lhs.command == rhs.command &&
    lhs.target_system == rhs.target_system &&
    lhs.target_component == rhs.target_component &&
    lhs.source_system == rhs.source_system &&
    lhs.source_component == rhs.source_component &&
    lhs.confirmation == rhs.confirmation &&
    lhs.from_external == rhs.from_external;
}

